size: var(--G-label-font-size); } .ml-form-option-text { color: var(--G-option-color); font-size: var(--G-option-font-size); font-weight: var(--G-option-font-weight); } .ml-form-option-description { color: var(--G-option-description-color); margin-left: calc(var(--G-option-size) + 0.5rem); } .ml-checkbox { --chkbg: var(--G-btn-pri-bg-color) !important; --chkfg: var(--G-checkbox-checkmark-color) !important; border-color: var(--G-input-border-color) !important; width: var(--G-option-size) !important; height: var(--G-option-size) !important; min-width: var(--G-option-size) !important; min-height: var(--G-option-size) !important; flex-shrink: 0; } .ml-radio { --chkbg: var(--G-btn-pri-bg-color) !important; border-color: var(--G-input-border-color) !important; background-color: white; width: var(--G-option-size) !important; height: var(--G-option-size) !important; min-width: var(--G-option-size) !important; min-height: var(--G-option-size) !important; flex-shrink: 0; } .ml-radio:checked { background-color: var(--chkbg)!important; } .ml-selected-badge { background-color: var(--G-btn-pri-bg-color) !important; color: var(--G-btn-pri-color) !important; border-color: var(--G-btn-pri-bg-color) !important; } .ml-site .border-b { border-color: var(--G-brand-border-color); } .ml-divider, .ml-survey-border { border-color: var(--G-brand-border-color); } .ml-results-divider { background-color: var(--G-brand-color); } progress::-webkit-progress-value { background-color: var(--G-brand-primary-color); } progress::-moz-progress-bar { background-color: var(--G-brand-primary-color); } .ml-popup-content .ml-popup-close:hover { color: var(--G-popup-close-hover-color)!important; } .ml-popup-teaser .ml-popup-close:hover { color: var(--G-popup-teaser-close-hover-color)!important; } </style><!-- Start builder preview area --><!--[--><div class="ml-landing-page" style=""><!--[--><div id="ikkhcKPKx8bXaaDL2CeSY" class="ml-section-wrapper" style="background-repeat:no-repeat;"><div class="md:px-8 max-w-6xl ml-animate mx-auto w-full px-4 lg:px-8"><div class="transition-all duration-150 empty:hidden" style="--row-padding-top-mobile:;--row-padding-bottom-mobile:;padding-top:0rem;padding-bottom:0rem;"><div class="gap-12 grid transition-all duration-150"><!--[--><div class="ml-desktop-layout relative" style=""><!--[--><!--[--><!-- Module wrapper in preview --><div class="grid items-center ml-mobile-cols-1 gap-8 gap-x-16 gap-y-12"><!--[--><div class="ml-column mobile:min-w-0" style=""><div class="list-group flex flex-col"><!--[--><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div root-parent-uuid="ikkhcKPKx8bXaaDL2CeSY"><!--[--><!-- Inline edit toolbar --><!--[--><!-- Preview mode: render content directly without wrapper divs --><!--[--><div class="transition-all duration-150 w-full" style="padding-bottom:2.0rem;--element-padding-bottom-mobile:;"><hr class="mx-auto" style="border-top: 1px solid #27272a; width: 100%"></div><!--]--><!--]--><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><!--]--></div></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><!--]--><!-- for preferences builder, show branding at the end of the contenct --></div></div></div></div><div id="Brands-3" class="ml-section-wrapper" style="background-repeat:no-repeat;"><div class="md:px-8 max-w-6xl ml-animate mx-auto w-full px-4 lg:px-8"><div class="transition-all duration-150 empty:hidden" style="--row-padding-top-mobile:;--row-padding-bottom-mobile:;padding-top:3.5rem;padding-bottom:2.0rem;"><div class="gap-8 grid transition-all duration-150"><!--[--><div class="ml-desktop-layout relative" style=""><!--[--><!--[--><!-- Module wrapper in preview --><div class="grid items-center ml-mobile-cols-1 gap-8 gap-x-8 gap-y-8"><!--[--><div class="ml-column mobile:min-w-0" style=""><div class="list-group flex flex-col"><!--[--><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="transition-all duration-150" style="padding-bottom:0rem;--element-padding-bottom-mobile:;" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><!-- Inline text edit type --><!-- Inline text toolbar --><!-- End of Inline text toobar --><!-- AI Suggestion --><!-- End of AI Suggestion --><!-- Preview mode: render sanitized HTML --><div><h2 class="ml-content-heading"><strong>Cómo un viejo desnudo con un casco romano y un escudo vikingo en mitad de la plaza del Duomo <u>me permitió llenar todos los horarios en mis negocios…</u></strong></h2><p class="ml-p ml-p-1"> </p><h3 class="ml-content-heading"><strong>Y cómo lo podés hacer también vos aplicando un detalle tan fácil que hará que le saques clientes a tu competencia</strong></h3></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="" style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><div class="ml-code-html">
<div class="ml-embedded" data-form="4YX9TK"></div></div><!--[--><!--]--><!--[--><!--]--><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="transition-all duration-150" style="padding-bottom:0rem;--element-padding-bottom-mobile:;" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><!-- Inline text edit type --><!-- Inline text toolbar --><!-- End of Inline text toobar --><!-- AI Suggestion --><!-- End of AI Suggestion --><!-- Preview mode: render sanitized HTML --><div><p class="ml-p ml-p-1"> Hola,</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Te voy a contar una historia muy fuera de lo común…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><strong>Después de que la leas, vas a entenderlo todo clarísimo clarísimo. Y cuando llegues al final de esta carta, no te va a quedar otro remedio que hacer lo que te digo y además contratarme para que vendas muchísimo más.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Comenzamos…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Esto pasó en…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Es más. ¿Por qué no venís conmigo a este viaje?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Agarrá tu abrigo porque hace un frío que quema las narices. Es diciembre. <br>Estamos por Milano y visitamos la Catedral de esta ciudad. El Duomo.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Mirá esta maravilla de mármol de más de 100 metros de altura. Hay palomas por todas partes. Torres que parecen lanzas o flechas que traspasan el cielo. Y estatuas… 3.400 para ser exactas.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Entremos…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Adentro hay silencio. Una luz súper tenue.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Hay vitrales de colores de escenas bíblicas. Cuadros de pinturas que cuelgan de sus pilares. Un altar enorme en el medio que no cabe en una sola foto.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Los turistas siguen llegando y llegando…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Después de unos minutos de andar recorriendo esta catedral, llegamos al final del</p><p class="ml-p ml-p-1">Paseo.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">El guía español nos deja con una frase antes de salir de nuevo al mundo exterior:</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><strong>—Esta catedral fue creada como un contraste entre la iglesia y el mundo. Acá dentro hay silencio, pero una vez que salgamos afuera…</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y apenas abre las puertas de la iglesia el barullo empieza a venir de todos lados…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Turistas hablando en diferentes idiomas. Una fila de corredores se abren paso entre la multitud tocando silbatos. Un golden le ladra a las palomas en la plaza…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Tanto ruido… tanta desconcentración…</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿Podés seguir el hilo de una conversación entre tanto ruido proveniente de todas partes?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿O escuchar una voz familiar y distinguirla entre la sirena de la policía o la banda que toca unos villancicos con instrumentos de vientos?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Es prácticamente imposible…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿No te parece?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><u>Allá afuera, como también acá dentro en internet, todos los días hay ruido, por todas partes.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Digo acá dentro porque la mayor parte del tiempo vivimos dentro de internet.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿O no está esa persona a tu lado mirando su celular ahora mismo?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Prácticamente ya estamos dentro.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Y por ahí dentro está pasando tu publicidad en este instante.</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>O tu posteo trending de tik tok…</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>O tu reel hablando sobre las características de tu producto</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>O tu carrusel diseñado con muchos colores</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Que enseguida se mezcla con el ruido de internet y nada más basta deslizar el dedo para que quien vea tu contenido, se olvide de él…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><u>PARA SIEMPRE.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y allá se fue…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Quizá nunca más se tope con él, nunca más se entere de qué era lo que estabas ofreciendo a fin de cuentas…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y si no descubriste aún por qué, acá está la razón:</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><u>Lo que estás haciendo ahí dentro es ruido.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><u>Irrelevante, repetitivo, a la moda.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><u>Ruido.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Y el ruido cuando se mezcla con el ruido, pasa desapercibido.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Es así…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Ahora…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Pongamos un escenario diferente…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿Qué pasaría si al salir del Duomo, y en medio de los miles de turistas hablando en diferentes idiomas, y de todo ese barullo de los corredores tocando silbatos y la banda de los villancicos, te encontrás a <strong>un anciano desnudo en medio de la plaza, con un casco romano en la cabeza, y sujetando un escudo vikingo en las manos</strong>?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿Seguirías mirando a la multitud de turistas?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿O tu atención se fijaría exclusivamente en el anciano desnudo?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">No sé qué tanto te guste mirar ancianos desnudos, pero yo creo que la curiosidad no te dejaría en paz hasta resolver la cuestión de<strong> QUÉ HACE UN ANCIANO DESNUDO EN UNA PLAZA.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><strong>¿En serio te parece que dejarías esa plaza, llegarías a tu hotel, cenarías unas horas más tarde y, al momento de cerrar los ojos…</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Te vendría inmediatamente a la cabeza la imagen de los turistas y los corredores tocando silbatos?</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>¡Claro que no!</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Nunca de los nunca.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>En cambio, toda tu atención, todos tus pensamientos, toda tu memoria, ¡se volcarían enseguida a recordar al viejo desnudo mitad romano mitad vikingo!</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y escuchá esto.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Puede que vos y yo no nos conozcamos de nada.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Pero nada de nada.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Sin embargo, una cosa sí sé.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y es que si estás acá, es porque te interesa vender tus cosas.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Así como yo…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y hacer plata y sentirte que alcanzaste algo importante con eso, y que tu novia te admire o tu novio o esposo, y que una ciudad lleve tu nombre y que te inviten a conferencias sobre ventas y congresos y etc…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Así como yo…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Entonces, si es así, vas a estar de acuerdo conmigo en que, para lograr todo eso, tenés que hacer que…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><u>Tu publicidad se quede prendida en la mente de tu futuro cliente, para que le quite el sueño y le haga recordar una y otra vez tu oferta, una y otra vez hasta que se tenga que preguntar «¿por qué china no compré?. Por qué si vi y me gustó y lo quise desde el primer instante a toda costa». Y entonces lo primero que haga mañana por la mañana va a ser volver por tu producto y comprarlo con tanto gusto que le dará una experiencia cósmica- orgásmica</u></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;">Y para que eso suceda tu publicidad no puede ser un turista ruidoso</p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>TIENE QUE SER UN VIEJO DESNUDO CON CASCO ROMANO Y ESCUDO VIKINGO</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿Y por qué, me vas a decir, si es tan fácil la gente no lo have?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Bueno, tengo la respuesta.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Pero que esto quede acá entre nosotros, y que no lo escuche tu competencia.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">O que lo escuche igual. No importa.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Total, van a seguir haciendo lo mismo que todos.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Acá va una verdad ultraverdadera:</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>A la gente le encanta seguir a la manada.</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Le en-can-ta.</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>A veces ni ellos se dan cuenta, ya que es algo gregario y, por ende, cómodo…</strong></p><p class="ml-p ml-p-1" style="text-align: center;"> </p><p class="ml-p ml-p-1"><strong>-No se necesita pensar diferente.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><strong>-No se requiere de mucho esfuerzo.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><strong>-No se arriesga nada.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Es fácil…</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Pero acá hay una cosa.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Y es que a veces la manada también está mal.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><u>SIEMPRE LA MANADA ESTÁ MAL.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">O cuando la gente vota a un candidato político, ¿acaso no elige al que tiene miles de antecedentes por corrupción?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">O cuando una mujer o un hombre se enamora, ¿no lo hacen del red flag más andante?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">O cuando hay que elegir algo que comer, ¿no gana la hamburguesa sobre el coliflor al vapor con una pizca de sal del Himalaya?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Aunque sea lo que más convenga, s<u>uele ser lo último que se prefiere</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">¿Y qué es lo que te dice la manada?</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">—Tenés que tener un millón de seguidores.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">—Publicar cosas divertidas para que se enganchen con tu contenido.</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">—Traerlos a todos a tus redes sociales y que se queden ahí…</p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1"><u>En cambio, vos no querés eso.</u></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1" style="text-align: center;"><strong>Te lo digo en serio. No lo querés.</strong></p><p class="ml-p ml-p-1"> </p><p class="ml-p ml-p-1">Porque esa gente es como el visitante casual de una tienda de ropas.</p><p class="ml-p ml-p-1"></p><p class="ml-p ml-p-1">Entra para ver qué hay, da una vuelta, toca los vestidos, las blusas, y dice: «Ay, que lindo».</p><p class="Predeterminado"> </p><p class="Predeterminado">Se da media vuelta y se va.</p><p class="Predeterminado"> </p><p class="Predeterminado">Con tus redes sociales es lo mismo.</p><p class="Predeterminado"> </p><p class="Predeterminado">Posteás algo y te dice: «Ay, que linda ropa».</p><p class="Predeterminado"> </p><p class="Predeterminado">Media vuelta y bye.</p><p class="Predeterminado"> </p><p class="Predeterminado">Por eso…</p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: justify;"> <strong> </strong></p><p class="Predeterminado" style="text-align: center;"><strong>Querés gente que compre, plata que entre en tu bolsillo, en tu banco</strong></p><p class="Predeterminado" style="text-align: center;"><strong> </strong></p><p class="Predeterminado" style="text-align: center;"><strong>La notificación en tu celular haciendo «¡clin!»…</strong></p><p class="Predeterminado" style="text-align: center;"><strong> </strong></p><p class="Predeterminado" style="text-align: center;"><strong>«Recibiste 1.000, 2.000. 3.000 dólares…»</strong></p><p class="Predeterminado" style="text-align: center;"><strong> </strong></p><p class="Predeterminado" style="text-align: center;"> </p><p class="Predeterminado">Y las redes sociales no suelen ser muy eficaces si querés lograr esto.</p><p class="Predeterminado"> </p><p class="Predeterminado">Y antes que me digas hereje, atendé:</p><p class="Predeterminado"> </p><p class="Predeterminado">La gente está tan encantada…</p><p class="Predeterminado"> </p><p class="Predeterminado">Agarran el celular, miran sus seguidores y piensan que esos son sus activos.</p><p class="Predeterminado"> </p><p class="Predeterminado">Pero ignoran que si el día de mañana, salen con un comentario del tipo «el cielo está verde, y me gusta ver monos copulando», te pueden cerrar la cuenta sin escala.</p><p class="Predeterminado"> </p><p class="Predeterminado">¿Y tus millones de seguidores?</p><p class="Predeterminado"><strong> </strong></p><p class="Predeterminado">Al tacho.</p><p class="Predeterminado"><strong> </strong></p><p class="Predeterminado">Así que, antes de ser ruido y mezclarte con la gente, deberías ser el viejo desnudo mitad  romano mitad vikingo.</p><p class="Predeterminado"> </p><p class="Predeterminado">Y a veces, la mejor forma de serlo, es simplemente haciendo algo que nadie hace:</p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: center;"><strong><u>PEDIR QUE TE COMPREN</u> </strong></p><p class="Predeterminado"> </p></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="" style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><div class="ml-code-html">
<div class="ml-embedded" data-form="4YX9TK"></div></div><!--[--><!--]--><!--[--><!--]--><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="transition-all duration-150" style="padding-bottom:0rem;--element-padding-bottom-mobile:;" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><!-- Inline text edit type --><!-- Inline text toolbar --><!-- End of Inline text toobar --><!-- AI Suggestion --><!-- End of AI Suggestion --><!-- Preview mode: render sanitized HTML --><div><h2 class="ml-content-heading"></h2><p class="Predeterminado">Sí. Es eso.</p><p class="Predeterminado"> </p><p class="Predeterminado">Así como lo leés.</p><p class="Predeterminado"> </p><p class="Predeterminado">Pedir que te compren…</p><p class="Predeterminado"> </p><p class="Predeterminado">En tu posteo.</p><p class="Predeterminado"> </p><p class="Predeterminado">En tu reel.</p><p class="Predeterminado"> </p><p class="Predeterminado">En tu tik tok.</p><p class="Predeterminado"> </p><p class="Predeterminado">Pedir que te compren.</p><p class="Predeterminado"> </p><p class="Predeterminado">Agregá una llamada a la acción a lo que sea que ofrezcas y soltá la orden.</p><p class="Predeterminado"> </p><p class="Predeterminado">-Comprá ahora</p><p class="Predeterminado"> </p><p class="Predeterminado">O también</p><p class="Predeterminado"> </p><p class="Predeterminado">-Reservá ahora</p><p class="Predeterminado"> </p><p class="Predeterminado">-Llamá ahora</p><p class="Predeterminado"> </p><p class="Predeterminado">-Escribí ahora</p><p class="Predeterminado"> </p><p class="Predeterminado">La gente necesita que le digas <strong>QUÉ TIENE QUE HACER.</strong></p><p class="Predeterminado"> </p><p class="Predeterminado">Y para que hagan lo que les digas, primero tenés que pedir.</p><p class="Predeterminado"> </p><p class="Predeterminado">La gente no lo hace.</p><p class="Predeterminado"> </p><p class="Predeterminado">¿O cuántas veces seguiste a una persona y nunca te enteraste de lo que vendía hasta que un día lo contó?</p><p class="Predeterminado"> </p><p class="Predeterminado">Las personas se pierden en tanto contenido que se olvida de lo básico.</p><p class="Predeterminado"> </p><p class="Predeterminado"> </p><p class="Predeterminado" style="text-align: center;"><strong>Que primero son vendedores, y después bailarines, actores o lo que sea que hagan en sus redes sociales.</strong></p><p class="Predeterminado" style="text-align: center;"><strong> </strong></p><p class="Predeterminado" style="text-align: justify;">Y te lo digo a vos.</p><p class="Predeterminado"> </p><p class="Predeterminado"><u>Tenés que ser vendedor, y solo así vas a poder generar dinero y dejar de perder tanto el tiempo.</u></p><p class="Predeterminado"> </p><p class="Predeterminado">Y te lo dice un abogado.</p><p class="Predeterminado"> </p><p class="Predeterminado">Que antes de ser abogado es vendedor.</p><p class="Predeterminado"> </p><p class="Predeterminado">Tengo dos empresas.</p><p class="Predeterminado"> </p><p class="Predeterminado">Un complejo de pádel y un lavadero de autos.</p><p class="Predeterminado"> </p><p class="Predeterminado">Y en todos mis negocios lo que busco es vender.</p><p class="Predeterminado"> </p><p class="Predeterminado">Tengo gente que colabora conmigo.</p><p class="Predeterminado"> </p><p class="Predeterminado">¿Pero sabés cuál es la única parte de mis negocios que no delego?</p><p class="Predeterminado"> </p><p class="Predeterminado"> </p><p class="Predeterminado" style="text-align: center;"><u>La parte de las ventas.</u></p><p class="Predeterminado" style="text-align: center;"><u> </u></p><p class="Predeterminado" style="text-align: center;"><u>Y la atención al cliente</u></p><p class="Predeterminado" style="text-align: center;"><u> </u></p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: justify;">Quiero estar siempre en contacto con ellos.</p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: justify;">Escuchar sus necesidades.</p><p class="Predeterminado" style="text-align: justify;"> </p><p class="Predeterminado" style="text-align: justify;">Sus agradecimientos y también sus reclamos.</p><p class="Predeterminado"> </p><p class="Predeterminado">¿Y cómo me va gracias a que no delego esa parte?</p><p class="Predeterminado"> </p><p class="Predeterminado">Bueno.</p><p class="Predeterminado"> </p><p class="Predeterminado">  </p><p class="Predeterminado" style="text-align: center;"><u>No tengo lugares disponibles</u></p><p class="Predeterminado" style="text-align: center;"><u> </u></p><p class="Predeterminado" style="text-align: center;"><u>Y las reseñas de mis clientes sobre mis servicios son magníficas</u></p></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" class="ml-mobile-flex flex transition-all duration-150 justify-center" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><div class="flex w-full" style="max-width:483px;"><!--[--><!--[--><!-- Inline edit toolbar --><!--[--><!-- Preview mode: render content directly without wrapper divs --><!--[--><img src="https://storage.mlcdn.com/account_image/1973466/WsK1ktmkAt4GVOEh470pWUIFNDAXDu8vAFrvFz9A.jpg" class="w-full" style="border-radius:0px;" loading="lazy" alt="" data-src="https://storage.mlcdn.com/account_image/1973466/WsK1ktmkAt4GVOEh470pWUIFNDAXDu8vAFrvFz9A.jpg" data-caption=""><!--]--><!--]--><!--]--><!--]--></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" class="ml-mobile-flex flex transition-all duration-150 justify-center" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><div class="flex w-full" style="max-width:483px;"><!--[--><!--[--><!-- Inline edit toolbar --><!--[--><!-- Preview mode: render content directly without wrapper divs --><!--[--><img src="https://storage.mlcdn.com/account_image/1973466/dcqDpYlBSbdyYUrKFVjPUNO7AcT85dNOUj9vNEgD.jpg" class="w-full" style="border-radius:0px;" loading="lazy" alt="" data-src="https://storage.mlcdn.com/account_image/1973466/dcqDpYlBSbdyYUrKFVjPUNO7AcT85dNOUj9vNEgD.jpg" data-caption=""><!--]--><!--]--><!--]--><!--]--></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" class="ml-mobile-flex flex transition-all duration-150 justify-center" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><div class="flex w-full" style="max-width:483px;"><!--[--><!--[--><!-- Inline edit toolbar --><!--[--><!-- Preview mode: render content directly without wrapper divs --><!--[--><img src="https://storage.mlcdn.com/account_image/1973466/6kJNBdXl3UvqkvSHNuhsiAaPngP9zCHmQDvIbujs.jpg" class="w-full" style="border-radius:0px;" loading="lazy" alt="" data-src="https://storage.mlcdn.com/account_image/1973466/6kJNBdXl3UvqkvSHNuhsiAaPngP9zCHmQDvIbujs.jpg" data-caption=""><!--]--><!--]--><!--]--><!--]--></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" class="ml-mobile-flex flex transition-all duration-150 justify-center" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><div class="flex w-full" style="max-width:483px;"><!--[--><!--[--><!-- Inline edit toolbar --><!--[--><!-- Preview mode: render content directly without wrapper divs --><!--[--><img src="https://storage.mlcdn.com/account_image/1973466/gKQJfZUZwSTmaZZZOGVNo8WsCvfgAm7b7YgoKaIq.jpg" class="w-full" style="border-radius:0px;" loading="lazy" alt="" data-src="https://storage.mlcdn.com/account_image/1973466/gKQJfZUZwSTmaZZZOGVNo8WsCvfgAm7b7YgoKaIq.jpg" data-caption=""><!--]--><!--]--><!--]--><!--]--></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="transition-all duration-150" style="padding-bottom:0rem;--element-padding-bottom-mobile:;" root-parent-uuid="Gx-Sx_rDAA8Al8c6U5Lyq"><!--[--><!-- Inline text edit type --><!-- Inline text toolbar --><!-- End of Inline text toobar --><!-- AI Suggestion --><!-- End of AI Suggestion --><!-- Preview mode: render sanitized HTML --><div><p class="ml-p ml-p-1"><span>Ahora…</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Voy a ser muy sincero contigo:</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Todo esto lo consigo gracias a que me formé como copywriter.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado" style="text-align: center;"><span><strong>Aprendí de ventas y escritura persuasiva de los mejores copywriters internacionales</strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Y sobre todo porque cada día salgo a vender.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Hago lo que dice el gran Claude Hopkins que debe hacer un verdadero publicista:</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span><u>«Algunos publicistas salen en persona y venden antes de pensar en escribir un anuncio. De este modo aprenden las reacciones de las distintas formas de argumentación y enfoque, aprenden lo que quieren los posibles compradores y los factores que no les atraen».</u></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Y esto es lo que mucha gente de marketing tiene que aprender.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado" style="text-align: center;"><span><strong>Se necesita menos creatividad, menos artistas haciendo anuncios, menos elaboración en campañas, menos colores y purpurinas Y MÁS VENDEDORES</strong></span></p><p class="Predeterminado" style="text-align: center;"><span><strong> </strong></span></p><p class="Predeterminado"><span>Y si tus textos, tus anuncios, tu email marketing (que es la mejor opción en vez de una red social donde podés perder tu cuenta por cualquier cosa) están hechos por un vendedor, y además un copywriter que sabe de lo que habla, y encima que lo aplica primero a sus negocios y por eso entiende de primera mano qué funciona, entonces sabés que la plata va a entrar.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Cómo sea.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>La plata termina llegando.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Te estoy diciendo.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Sé muy bien de lo que hablo:</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span><strong>Sé comunicar mi mensaje y lo sé comunicar RENTABLEMENTE BIEN.</strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Gracias a experiencias y pruebas y estudios.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Y los mismos principios que aplico para ganarme la vida de una manera holgada y cómoda, sin pasarme cientos de horas encima, lo podemos aplicar también a tus negocios.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Mirá que dije <u>holgada y cómoda.</u></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado" style="text-align: center;"><span><strong>Porque no hay nada más fácil que aplicar esto. Sabiendo el enfoque y las técnicas que más convienen a lo que estés vendiendo.</strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Haciéndolo de una manera tan adictivamente persuasiva, que al que lea tu oferta, le sea imposible decirte que no.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Ahora…</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Sólo ofrezco mis servicios a 1 empresa por sector.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>¿Por qué?</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado" style="text-align: center;"><span><strong>Porque te voy a dar exclusividad.</strong></span></p><p class="Predeterminado"><span><strong> </strong></span></p><p class="Predeterminado" style="text-align: center;"><span><strong><u>Y a todos nos gusta ser exclusivos.</u></strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>¿Y qué vas a tener de mí?</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span><strong>Todo.</strong></span></p><p class="Predeterminado"><span><strong> </strong></span></p><p class="Predeterminado"><span><strong>O casi todo.</strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>—Mientras seas mi cliente, voy a comer, dormir, bañarme, meditar, mientras pienso en las mejores estrategias de cómo hacer que vendas más.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>—Seriedad en los plazos. Si te digo que te entrego un trabajo el viernes, te entrego el viernes. Por eso mismo: pocos clientes, pero con la certeza de que si quedamos en una fecha, será esa fecha.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>—No me vas a ver despareciendo apenas cobre. Eso habla mal de mí. Odio la gente así, y por lo tanto, odiaría hacerle lo mismo a alguien. REGLA DE ORO.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>—Estoy motivado. Parece poca cosa pero… ¿Ya trabajaste con alguien desmotivado? Es como si le estuvieras haciendo un favor. No hay nada peor que eso. Repito: por eso trabajo con 1 empresa por sector. Hace que el cansancio sea mucho menos. Siempre estás con la mente clara.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>—Te trato bien. Ser hijo de puta no vende.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>—Cambiamos el texto hasta que te guste. Hasta que sientas que te funciona.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado" style="text-align: justify;"><span><u>Y lo estoy diciendo tan en serio que si me retraso en los plazos de entrega, te devuelvo tu dinero.</u></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Pero así también.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>El pago debo recibirlo 10 días antes de empezar el trabajo.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Y aparte de esto…</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Vas a tener que dejarme trabajar para producir los resultados.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Si no hacemos de la manera que te digo, no me interesa trabajar contigo.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Ni si me ofrecés todo el oro del mundo voy a comprometer mi trabajo y la calidad de mis servicios.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Si vamos a trabajar, <u>me vas a hacer caso a mí.</u></span></p><p class="Predeterminado"><span><strong> </strong></span></p><p class="Predeterminado" style="text-align: justify;"><span><strong>Asi que…</strong></span></p><p class="Predeterminado" style="text-align: justify;"><span> </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span><strong>Si querés saber cómo hacer ofertas irresistibles que la gente vea y tenga que comprarte lo que sea que ofrezcas, abajo un formulario para que hablemos.</strong></span></p><p class="Predeterminado"><span><strong> </strong></span></p><p class="Predeterminado"><span style="color: rgb(255, 38, 0);"><strong> </strong></span></p><p class="Predeterminado"><span style="color: rgb(255, 38, 0);"> </span></p><p class="Predeterminado"><span>Que estés bien,</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>SANTY</span></p><p class="Predeterminado"><span><strong> </strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>PD: Si estás pensando que contratar mis servicios de copywriting va a representar un gasto innecesario más a tu empresa y que, en su lugar, podés pedirle a tu primo licenciado en letras que te escriba algo lindo para tus redes sociales, dejame decirte esto:</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>De las cien maneras que tiene un negocio de gastar dinero, sólo hay una que genera ingresos. <u>Y esa es la venta.</u></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Y no creo que quieras dejar esa <strong>responsabilidad</strong> a alguien que solamente sabe hilar una oración.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>No se trata de escribir lindo, saber gramática, o imitar la publicidad de otros. </span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>En cambio, de lo que sí se trata es de usar los mejores ángulos psicológicos para el tipo de cliente específico que tenés.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>E investigar por vos.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Investigar muchísimo.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span><strong>Porque eso sí hace un buen copywriter. </strong></span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Y no lo va a hacer ChatGPT.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Bueno, lo mismo que te dijo a vos, probablamente le diga a cien personas más que le pidieron una frase sorprendente para vender X cosa.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Ya le parece a tu tío con cinco familias que todavía utiliza el mismo discurso de galán.</span></p><p class="Predeterminado"><span> </span></p><p class="Predeterminado"><span>Dale. Completá este formulario y hablemos. </span></p></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><!--]--></div></div><!--]--></div><!--]--><!-- End of module wrapper in preview --><!--]--></div><!--]--><!-- for preferences builder, show branding at the end of the contenct --></div></div></div></div><div id="One-column" class="ml-section-wrapper" style="background-repeat:no-repeat;"><div class="md:px-8 max-w-6xl ml-animate mx-auto w-full px-4 lg:px-8"><div class="transition-all duration-150 empty:hidden" style="--row-padding-top-mobile:;--row-padding-bottom-mobile:;padding-top:0rem;padding-bottom:0rem;"><div class="gap-12 grid transition-all duration-150"><!--[--><div class="ml-desktop-layout relative" style=""><!--[--><!--[--><!-- Module wrapper in preview --><div class="grid items-center ml-mobile-cols-1 gap-8 gap-x-16 gap-y-12"><!--[--><div class="ml-column mobile:min-w-0" style=""><div class="list-group flex flex-col"><!--[--><div class="list-group-item"><!--[--><!--[--><!-- Module wrapper in preview --><div class="" style="padding-bottom:1.5rem;--element-padding-bottom-mobile:;" root-parent-uuid="DT_MebUsEAAwiAoDDYUGq"><!--[--><div class="ml-code-html">
