            }
            else { // redirect
                toggle_loader(submitButton, false);
                if (submitButton.dataset.redirectAction === 'link' && submitButton.dataset.redirectActionValue) {  // link or success
                    const target = submitButton.querySelector('a')?.target || '_blank';
